package com.faymaz.herkul.data

data class Hadith(
    val arabic: String,
    val turkish: String,
    val english: String,
    val narrator: String,
    val source: String
)

object Hadiths {
    val ALL = listOf(
        Hadith("بِسْمِ اللّٰهِ الرَّحْمَانِ الرَّحِيمِ مِفْتَاحُ كُلِّ كِتَابٍ", "Bütün semâvî kitâbların anahtarı, Besmele-i Şerîfe’dir.", "The key to all heavenly books is the Basmala (In the name of Allah, the Most Gracious, the Most Merciful).", "Ali ibn Abi Talib (r.a.)", "Câmi’u’s-sağîr"),
        Hadith("اَلْحَمْدُ عَلٰي النِّعْمَةِ أَمَانٌ لِزَوَالِهِ", "Cenâb-ı Hakk’ın ni’metlerine şükür, o ni’metin zevâline (yok olmasına) emândır.", "Gratitude for Allah's blessings is a safeguard against their loss.", "Abu Hurayrah (r.a.)", "Deylemî"),
        Hadith("اِنَّ اَوْلَي النَّاسِ بِي اَكْثَرُهُمْ عَلَيَّ صَلاَةً", "Sizden bana en yakın olan kimse, bana çokça salevât getirendir.", "The closest people to me are those who send the most blessings upon me.", "Abu Hurayrah (r.a.)", "Câmi’u’s-sağîr"),
        Hadith("لاَيَقْبَلُ اللّٰهُ اِيمَانًا بِلاَعَمَلٍ وَلاَعَمَلاً بِلاَاِيمَانٍ", "Cenâb-ı Allah amelsiz îmânı ve îmânsız da ameli kabûl buyurmaz.", "Allah does not accept faith without deeds, nor deeds without faith.", "Abu Hurayrah (r.a.)", "Menâvî"),
        Hadith("اِنَّمَا الْأَعْمَالُ بِالنِّيّٰاتِ", "Ameller niyetlere göredir.", "Actions are judged by intentions.", "Umar ibn al-Khattab (r.a.)", "Menâvi"),
        Hadith("اَلْمَرْءُ مَعَ مَنْ اَحَبَّ", "Kişi sevdiği ile beraberdir.", "A person will be with those whom he loves.", "Anas ibn Malik (r.a.)", "Buhârî, Müslim"),
        Hadith("اِنَّ اللّٰهَ تَعَالٰي يُعْطِي الدُّنْيَا عَلٰي نِيَّةِ الْاٰخِرَةِ", "Âhiret saâdeti için çalışanlara Cenâb-ı Hakk dünya saâdetini de ihsân buyurur.", "Allah grants worldly success to those who work for the Hereafter.", "Abu Hurayrah (r.a.)", "Deylemî"),
        Hadith("اَلنِّيَّةُ الْحَسَنَةُ تُدْخِلُ صَاحِبَهَا الْجَنَّةَ", "Cenâb-ı Hakk’ın rızâsını kazanmak için beslenen güzel niyet, sâhibini cennete dâhil eder.", "A good intention will admit its owner to Paradise.", "Abu Hurayrah (r.a.)", "Deylemî"),
        Hadith("أَخْلَصْ دِينَكَ يَكْفِيكَ الْعَمَلُ الْقَلِيلُ", "İbâdetini riyâ (gösteriş), garaz (bozuk niyet) ve ivazdan (karşılık beklemekten) hâlis et (temizle). Bu halde az bir amel senin için kâfîdir (yeterlidir).", "Purify your religion, and a little deed will suffice for you.", "Abu Hurayrah (r.a.)", "Münâvî"),
        Hadith("لاَيُؤْمِنُ عَبْدٌ حَتّٰي يَكُونَ قَلْبُهُ وَلِسَانُهُ سَوَاءً", "Lisan ile kalp bir olmadıkça hiçbir kul, mü’min-i kâmil olmaz.", "A servant does not truly believe until his heart and tongue are in harmony.", "Abu Hurayrah (r.a.)", "Kenzü’l İrfân"),
        Hadith("تَزَوَّجُوا فَاِنِّي اُبَاهِي بِكُمُ الْاُمَمَ", "Evlenin çünkü ben diğer ümmetlere karşı sizin çokluğunuzla iftihar edeceğim.", "Marry, for I will take pride in your numbers before other nations.", "Anas ibn Malik (r.a.)", "Buhârî, Müslim"),
        Hadith("أَنَا وَكَافِلُ الْيَتِيمِ فِي الْجَنَّةِ هٰكَذَا", "Yetimi himâye eden cennette şöylece benimle beraberdir. (Resûlullâh (s.a.v.) ‘hâkezâ’ derken şahâdet parmağıyla orta parmağını aralıklı açarak göstermiştir.)", "The one who takes care of an orphan will be with me in Paradise like this. (The Prophet pointed with his index and middle fingers, holding them slightly apart.)", "Sahl ibn Sa'd (r.a.)", "Buhârî"),
        Hadith("طَلَبُ الْحَلاَلِ جِهَادٌ", "Helâlinden kazanmak hak yolunda yapılan muhârebe kadar ecirlidir.", "Seeking lawful earnings is like striving in the way of Allah.", "Abu Hurayrah (r.a.)", "Deylemî"),
        Hadith("أَفْضَلُ الْمُؤْمِنِينَ اَحْسَنُهُمْ خُلُقًا", "Mü’minin en fazîletlisi, ahlâkı en güzel olanıdır.", "The most virtuous of believers is the one with the best character.", "Abu Huraira (r.a.)", "Buhârî"),
        Hadith("قَيِّدُوا الْعِلْمَ بِالْكِتَابَةِ", "İlmi kitâbetle; yani yazarak bağlayın.", "Preserve knowledge by writing it down.", "Abu Hurayrah (r.a.)", "Tirmizî"),
        Hadith("مَنْ دَلَّ عَلٰي خَيْرٍ فَلَهُ أَجْرُ فَاعِلِهِ", "Kim bir hayra delâlet ederse onu işleyen gibi ecir alır.", "Whoever guides to good has a reward similar to the one who does it.", "Abu Mas'ud al-Ansari (r.a.)", "Beyhakî"),
        Hadith("قَيِّدْ وَتَوَكَّلْ", "Deveni bağla, ondan sonra Allah’a tevekkül et.", "Tie your camel, then trust in Allah.", "Anas ibn Malik (r.a.)", "Tirmizî"),
        Hadith("بُعِثْتُ لِاُتَمِّمَ مَكَارِمَ الْاَخْلاَقِ", "Ben güzel ahlâkı tamamlamak üzere peygamber ba’s olundum (gönderildim).", "I was sent to perfect good character.", "Abu Huraira (r.a.)", "Buhârî, Müslim"),
        Hadith("لَيْسَ الْغِنٰي عَنْ كَثْرَةِ الْعَرَضِ وَلٰكِنَّ الْغِنٰي غَنِيَ النَّفْسِ", "Zenginlik arâzî ve mal çokluğundan ibâret değildir. Asıl zenginlik kalp zenginliği yani kanaattir.", "Wealth is not in having many possessions, but true wealth is the richness of the soul (contentment).", "Abu Huraira (r.a.)", "Müslim"),
        Hadith("خَيْرُ الْأُمُورِ اَوْسَاطُهَا", "İşlerin hayırlısı ortalarıdır. Yani ifrat ve tefritten âzâde (aşırılıktan uzak), mu’tedil (orta) olandır.", "The best of matters are those moderate, free from extremes.", "Abu Hurayrah (r.a.)", "Beyhakî"),
        Hadith("اِنَّ مِنَ السَّرَفِ اَنْ تَأْكُلَ كُلَّ مَآاِشْتَحَيْتَ", "Canın her istediğini yemek de israf cümlesindendir.", "Eating everything you desire is also a form of wastefulness.", "Miqdam ibn Ma'dikarib (r.a.)", "Ebû Dâvud"),
        Hadith("طُوبٰي لِمَنْ طَالَ عُمْرُهُ وَحَسُنَ عَمَلُهُ", "Ömrü uzun ve ameli hareketi, işi ve ibâdeti güzel olan kimseye ne mutlu!", "Blessed is the one whose life is long and whose deeds are good!", "Abu Hurayrah (r.a.)", "Taberânî"),
        Hadith("أَحَبُّ الْاَعْمَالِ اِلٰي اللّٰهِ اَدْوَمُهَا وَاِنْ قَلَّ", "Amellerin Allah’a en sevgilisi, az da olsa devamlı olanıdır.", "The most beloved of deeds to Allah are those done consistently, even if they are small.", "Aisha (r.a.)", "Buhârî"),
        Hadith("اِذَا جَاءَ اَحَدَكُمْ اَلْجُمْعَةَ فَلْيَغْتَسِلْ", "Sizden herhangi biriniz Cumâ namazına gideceği zaman gusletsin.", "When one of you comes to Friday prayer, let him perform ghusl (full ablution).", "Abu Sa'id al-Khudri (r.a.)", "Buhârî, Müslim"),
        Hadith("عَامَّةُ عَذَابِ الْقَبْرِ مِنَ الْبَوْلِ", "Kabir azâbının çoğu idrardan temizlenmeye ehemmiyet vermemektendir.", "Most of the punishment of the grave is due to negligence in cleaning oneself from urine.", "Ibn Abbas (r.a.)", "İbn Mâce, Nesaî"),
        Hadith("اَلسِّوَاكُ شِفٰاءُ مِنْ كُلِّ دَاءٍ اِلاَّ السَّامُ اَلسَّامُ الْمَوْتُ", "Dişleri misvak ile temizlemek ölümden başka bütün hastalıkların mühim bir kısmına şifâdır.", "Using the miswak (tooth stick) is a cure for all diseases except death.", "Aisha (r.a.)", "Keşfü’l hafâ, Deylemî"),
        Hadith("اَلنَّظَافَةُ تَدْعُوا اِلٰي الْاِيمَانِ", "Temizliğe itinâ ve devamlılık, insanı tam bir îmâna da’vet eder.", "Cleanliness invites to faith.", "Abu Hurayrah (r.a.)", "Taberânî"),
        Hadith("اِذَا تَوَضَّأَ اَحَدُكُمْ فَهُوَ فِي صَلاَةٍ مَالَمْ يُحْدِثْ", "Sizden birisi abdestli bulunmak niyetiyle abdest alırsa, abdesti bozulmadıkça namazda bulunmuş gibi ecir alır.", "When one of you performs ablution with the intention of remaining in a state of purity, he receives the reward of being in prayer as long as his ablution is not nullified.", "Abu Hurayrah (r.a.)", "Münâvî"),
        Hadith("اَحْسِنُوا اِقَامَةَ الصُّفُوفِ فِي الصَّلاَةِ", "Namazda safları iyi doğrultunuz, yani bir hizâda ve muntazam tutunuz.", "Perfect the straightening of rows in prayer.", "Nu'man ibn Bashir (r.a.)", "Müslim"),
        Hadith("اِذَا دَخَلَ اَحَدُكُمْ اَلْمَسْجِدَ فَلاَ يَجْلِسْ حَتّٰي يُصَلِّيَ رَكْعَتَيْنِ", "Sizden biriniz mescide girdiği zaman iki rek’at namaz kılmadıkça oturmasın.", "When one of you enters the mosque, let him not sit until he prays two units (rak'ahs).", "Abu Qatada (r.a.)", "Müslim"),
        Hadith("اَوَّلُ تُحْفَةُ الْمُؤْمِنِ اَنْ يُغْفَرَ لِمَنْ صَلّٰي عَلَيْهِ", "Mü’minin öldükten sonra verilmesine sebeb olduğu ilk hediyesi, cenâze namazını kılan kimsenin Allah katından mağfiret dilemesidir.", "The first gift for the believer is that those who pray the funeral prayer for him seek forgiveness from Allah.", "Abu Hurayrah (r.a.)", "Deylemî"),
        Hadith("لِكُلِّ شَيْءٍ زَكَاةٌ وَزَكَاةُ الْجَسَدِ الصَّوْمُ", "Her şeyin bir zekâtı vardır. Cesedin zekâtı da oruçtur.", "Everything has a charity, and the charity of the body is fasting.", "Abu Huraira (r.a.)", "İbn-i Mâce"),
        Hadith("مَنْ اِعْتَكَفَ عَشْرًا فِي رَمَضَانَ كَانَ كَحَجَّتَيْنِ وَ عُمْرَتَيْنِ", "Kim ramazanın son on gününde itikâf ederse iki hac ve iki umre sevabı alır.", "Whoever observes i'tikaf (spiritual retreat) for ten days in Ramadan will have the reward of two pilgrimages and two umrahs.", "Ibn Abbas (r.a.)", "Suyûtî, Dürru’l Mensûr"),
        Hadith("اِذَا أَدَّيْتَ زَكَاةَ مَالِكَ فَقَدْ قَضَيْتَ مَا عَلَيْكَ", "Malının zekâtını ödediğin zaman artık üzerinde olan borcunu yerine getirmiş olursun.", "When you have paid the zakat (charity) of your wealth, you have fulfilled what is upon you.", "Abu Huraira (r.a.)", "Buhârî"),
        Hadith("اِذَا تَصَدَّقْتَ فَأَمْضِهَا", "Sadaka vereceğin zaman geciktirme.", "When you give charity, do it immediately.", "Abu Dharr (r.a.)", "Müsned"),
        Hadith("أَفْضَلُ الصَّدَقَةِ سَقْيُ الْمَاءِ", "Sadakaların en fazîletlisi su içirmek ve su hayrı yapmaktır.", "The best charity is providing water.", "Sa'd ibn Ubadah (r.a.)", "Ahmed bin Hanbel"),
        Hadith("اَلْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ", "Hakiki Müslüman, diğer Müslümanların elinden ve dilinden emin olduğu kimsedir.", "A true Muslim is one from whose tongue and hand other Muslims are safe.", "Abdullah ibn Amr (r.a.)", "Buhârî, Müslim"),
        Hadith("لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ", "Sizden biriniz, kendisi için istediğini kardeşi için de istemedikçe tam îmân etmiş olamaz.", "None of you truly believes until he loves for his brother what he loves for himself.", "Anas ibn Malik (r.a.)", "Buhârî, Müslim"),
        Hadith("اَلْمُؤْمِنُ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا", "Mü’minler birbirine karşı tıpkı bir binanın taşları gibi birbirini tutup kuvvetlendirir.", "The believer to the believer is like a building, each part strengthening the other.", "Abu Musa al-Ash'ari (r.a.)", "Buhârî, Müslim"),
        Hadith("مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ طَرِيقًا إِلَى الْجَنَّةِ", "Kim ilim aramak için bir yola girerse, Allah onun için cennete giden bir yolu kolaylaştırır.", "Whoever travels a path in search of knowledge, Allah will make easy for him a path to Paradise.", "Abu Darda (r.a.)", "Sunan Abu Dawud, Tirmidhi, Ibn Majah"),
        Hadith("طَلَبُ الْعِلْمِ فَرِيضَةٌ عَلَى كُلِّ مُسْلِمٍ", "İlim öğrenmek her müslümana farzdır.", "Seeking knowledge is obligatory upon every Muslim.", "Anas ibn Malik (r.a.)", "Sunan Ibn Majah"),
        Hadith("خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ", "Sizin en hayırlınız Kuran'ı öğrenen ve öğretendir.", "The best among you are those who learn the Quran and teach it.", "Uthman ibn Affan (r.a.)", "Sahih Bukhari"),
        Hadith("مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ", "Allah'a ve ahiret gününe iman eden ya hayır söylesin ya da sussun.", "Whoever believes in Allah and the Last Day should speak good or remain silent.", "Abu Hurayrah (r.a.)", "Sahih Bukhari, Sahih Muslim"),
        Hadith("الْجَنَّةُ تَحْتَ أَقْدَامِ الْأُمَّهَاتِ", "Cennet annelerin ayakları altındadır.", "Paradise lies under the feet of mothers.", "Muawiyah ibn Jahima (r.a.)", "Sunan an-Nasa'i"),
        Hadith("الدِّينُ النَّصِيحَةُ", "Din nasihattir (öğüttür).", "Religion is sincere advice (nasihah).", "Tamim ad-Dari (r.a.)", "Sahih Muslim"),
        Hadith("الْحَلَالُ بَيِّنٌ وَالْحَرَامُ بَيِّنٌ", "Helal açıktır, haram da açıktır.", "The lawful is clear and the unlawful is clear.", "Nu'man ibn Bashir (r.a.)", "Sahih Bukhari, Sahih Muslim"),
        Hadith("إِنَّ اللَّهَ طَيِّبٌ لَا يَقْبَلُ إِلَّا طَيِّبًا", "Şüphesiz Allah temizdir, sadece temiz olanı kabul eder.", "Verily, Allah is pure and accepts only that which is pure.", "Abu Hurayrah (r.a.)", "Sahih Muslim, Tirmidhi"),
        Hadith("اتَّقِ اللَّهَ حَيْثُمَا كُنْتَ", "Nerede olursan ol Allah'tan kork.", "Fear Allah wherever you are.", "Abu Dharr & Muadh ibn Jabal (r.a.)", "Tirmidhi, Ahmad"),
        Hadith("لَا ضَرَرَ وَلَا ضِرَارَ", "Zarar vermek ve zarara karşılık zarar vermek yoktur.", "There should be neither harming nor reciprocating harm.", "Abu Sa'id al-Khudri (r.a.)", "Ibn Majah, Malik's Muwatta"),
        Hadith("أَلَا أُخْبِرُكُمْ بِمَنْ تَحْرُمُ عَلَيْهِ النَّارُ كُلُّ هَيِّنٍ لَيِّنٍ سَهْلٍ قَرِيبٍ", "Size cehenneme girmeyecek kimseleri bildireyim mi? Cana yakın, uysal, yumuşak huylu ve kolay geçinilen herkes.", "Shall I not tell you about those for whom the Fire is forbidden? Every gentle, easygoing, soft-natured and approachable person.", "Ibn Mas'ud (r.a.)", "Tirmizî, Sıfatü'l-Kıyâme 45"),
        Hadith("لَا يَدْخُلُ الْجَنَّةَ قَاطِعٌ", "Akrabasıyla ilgisini kesen kimse cennete giremez.", "The one who severs ties of kinship will not enter Paradise.", "Jubayr ibn Mut'im (r.a.)", "Buhârî, Edeb 11"),
        Hadith("لَتُؤَدُّنَّ الْحُقُوقَ إِلَى أَهْلِهَا يَوْمَ الْقِيَامَةِ حَتَّى يُقَادَ لِلشَّاةِ الْجَلْحَاءِ مِنَ الشَّاةِ الْقَرْنَاءِ", "Kıyamet gününde haklar sahiplerine geri verilecektir. Boynuzlu koyundan boynuzsuz koyunun bile öcü alınacaktır.", "Rights will certainly be restored to their owners on the Day of Resurrection, to the extent that even a hornless sheep will have its due taken from the horned sheep.", "Abu Hurairah (r.a.)", "Müslim, Birr 60"),
        Hadith("رَكْعَتَا الْفَجْرِ خَيْرٌ مِنَ الدُّنْيَا وَمَا فِيهَا", "Sabah namazının iki rekat sünneti, dünya ve dünyadaki her şeyden daha hayırlıdır.", "The two rak'ahs of Fajr are better than the world and everything in it.", "Aisha (r.a.)", "Müslim, Müsâfirîn 96"),
        Hadith("مَنْ قَالَ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ غُرِسَتْ لَهُ نَخْلَةٌ فِي الْجَنَّةِ", "Bir kimse 'sübhânallahi ve bi-hamdihî' derse, cennette onun için bir hurma ağacı dikilir.", "Whoever says 'SubhanAllahi wa bihamdihi' (Glory be to Allah and His is the praise), a palm tree is planted for him in Paradise.", "Jabir ibn Abdullah (r.a.)", "Tirmizî 3464"),
        Hadith("إِنَّ اللَّهَ يَقْبَلُ تَوْبَةَ الْعَبْدِ مَا لَمْ يُغَرْغِرْ", "Bir kul can çekişmeye başlamadığı sürece, Allah Teâlâ onun tövbesini kabul eder.", "Indeed, Allah accepts the repentance of a servant as long as he has not yet reached the death rattle.", "Ibn Umar (r.a.)", "Tirmizî, Daavât 98"),
        Hadith("فِي اللَّيْلِ سَاعَةً لَا يُوَافِقُهَا رَجُلٌ مُسْلِمٌ يَسْأَلُ اللَّهَ خَيْرًا مِنْ أَمْرِ الدُّنْيَا وَالْآخِرَةِ إِلَّا أَعْطَاهُ إِيَّاهُ وَذَلِكَ كُلَّ لَيْلَةٍ", "Geceleyin öyle bir zaman vardır ki, müslüman bir kimse o zamana rastlayıp Allah'tan dünya ve âhirete dair hayırlı bir şey dilerse, Allah ona dilediğini verir. Bu her gece böyledir.", "In the night there is a moment in which no Muslim asks Allah for any good of this world or the Hereafter, except that He grants it to him. And that is every single night.", "Jabir ibn Abdullah (r.a.)", "Müslim, Müsâfirîn 166"),
        Hadith("مِفْتَاحُ الْجَنَّةِ الصَّلَاةُ وَمِفْتَاحُ الصَّلَاةِ الطُّهُورُ", "Cennetin anahtarı namazdır, namazın anahtarı da abdesttir.", "The key to Paradise is prayer, and the key to prayer is purification (ablution).", "Ali ibn Abi Talib (r.a.)", "Tirmizî, Tahâret 1"),
        Hadith("يَسِّرُوا وَلَا تُعَسِّرُوا وَبَشِّرُوا وَلَا تُنَفِّرُوا", "Kolaylaştırınız, zorlaştırmayınız. Müjdeleyiniz, nefret ettirmeyiniz.", "Make things easy and do not make them difficult. Give glad tidings and do not drive people away.", "Anas ibn Malik (r.a.)", "Buhârî, İlim 11"),
        Hadith("يَا مُقَلِّبَ الْقُلُوبِ ثَبِّتْ قَلْبِي عَلَى دِينِكَ", "Ey kalpleri (halden hale) çeviren Allahım! Benim kalbimi dinin üzerinde sabit kıl.", "O Turner of hearts, keep my heart firm upon Your religion.", "Anas ibn Malik (r.a.)", "Tirmizî, Kader 7"),
        Hadith("أَنَا زَعِيمٌ بِبَيْتٍ فِي وَسَطِ الْجَنَّةِ لِمَنْ تَرَكَ الْكَذِبَ وَإِنْ كَانَ مَازِحًا", "Şakadan bile olsa yalan söylemeyen kimseye cennetin ortasında bir köşk verileceğine kefilim.", "I guarantee a house in the middle of Paradise for the one who abandons lying even when joking.", "Abu Umamah al-Bahili (r.a.)", "Tirmizî"),
        Hadith("كُلُوا الزَّيْتَ وَادَّهِنُوا بِهِ فَإِنَّهُ مِنْ شَجَرَةٍ مُبَارَكَةٍ", "Zeytinyağı yiyiniz ve onunla vücudunuzu yağlayınız; çünkü zeytinyağı mübarek bir ağaçtan çıkar.", "Eat olive oil and anoint yourselves with it, for it comes from a blessed tree.", "Umar ibn al-Khattab (r.a.)", "Tirmizî, Et'ime 43"),
        Hadith("اللَّهُمَّ نَقِّنِي مِنْ خَطَايَايَ كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنَ الدَّنَسِ", "Allah'ım! Beyaz elbisenin kirden arınması gibi, sen de beni hatalardan arındır.", "O Allah, cleanse me of my sins as a white garment is cleansed of filth.", "Abu Hurairah (r.a.)", "Buhârî, Ezân 89"),
        Hadith("إِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَ", "Allah ancak, merhametli kullarına rahmet eder.", "Allah shows mercy only to those of His servants who are merciful.", "Usamah ibn Zayd (r.a.)", "Müslim, Cenâiz 11; Buhârî, Merdâ 9"),
        Hadith("اللَّهُمَّ اغْفِرْ لِي ذَنْبِي وَوَسِّعْ لِي فِي دَارِي وَبَارِكْ لِي فِي رِزْقِي", "Allahım! Günahımı bağışla. Bana evimde bolluk ver. Rızkımı benim için bereketlendir.", "O Allah, forgive my sin, grant me spaciousness in my home, and bless my provision for me.", "Abu Hurairah (r.a.)", "Tirmizî, Daavât 79"),
        Hadith("وَمَا تَوَاضَعَ أَحَدٌ لِلَّهِ إِلَّا رَفَعَهُ اللَّهُ", "Allah için tevazu gösteren kişiyi Allah ancak yüceltir.", "No one humbles himself for the sake of Allah except that Allah raises him.", "Abu Hurairah (r.a.)", "Müslim, Birr 69"),
        Hadith("بِسْمِ اللَّهِ الَّذِي لَا يَضُرُّ مَعَ اسْمِهِ شَيْءٌ فِي الْأَرْضِ وَلَا فِي السَّمَاءِ وَهُوَ السَّمِيعُ الْعَلِيمُ", "Kim her sabah ve her akşam 3 defa: 'İsmi sayesinde yerde ve gökte hiçbir şeyin zarar veremeyeceği Allah'ın adıyla. O her şeyi işitir ve bilir.' derse, ona hiçbir şey zarar vermez.", "Whoever says three times in the morning and evening: 'In the name of Allah, with Whose name nothing on earth or in heaven can cause harm, and He is the All-Hearing, the All-Knowing', nothing will harm him.", "Uthman ibn Affan (r.a.)", "Ebû Dâvûd, Edeb 101; Tirmizî, Daavât 13"),
        Hadith("اللَّهُمَّ قَنِّعْنِي بِمَا رَزَقْتَنِي وَبَارِكْ لِي فِيهِ وَاخْلُفْ عَلَيَّ كُلَّ غَائِبَةٍ لِي بِخَيْرٍ", "Allahım! Bana verdiğin rızık konusunda beni kanaat sahibi yap ve o rızkımı bereketli kıl. Zayi olan her nimetin daha hayırlısını bana ihsan eyle.", "O Allah, make me content with what You have provided me, bless me in it, and replace every absence in my life with something better.", "Abu Hurairah (r.a.)", "Silsiletü's-Sahîha"),
        Hadith("مَا أَكَلَ أَحَدٌ طَعَامًا قَطُّ خَيْرًا مِنْ أَنْ يَأْكُلَ مِنْ عَمَلِ يَدِهِ", "Hiçbir kimse, asla kendi kazancından daha hayırlı bir rızık yememiştir.", "No one has ever eaten food better than that which he earned with his own hands.", "al-Miqdam ibn Ma'dikarib (r.a.)", "Buhârî, Büyû' 15, Enbiyâ 37"),
        Hadith("أَفْضَلُ الذِّكْرِ لَا إِلَهَ إِلَّا اللَّهُ", "Zikrin en faziletlisi lâ ilâhe illallah'tır.", "The best remembrance is 'La ilaha illallah' (There is no god but Allah).", "Jabir ibn Abdullah (r.a.)", "Tirmizî, Daavât 9"),
        Hadith("اقْرَءُوا الْقُرْآنَ فَإِنَّهُ يَأْتِي يَوْمَ الْقِيَامَةِ شَفِيعًا لِأَصْحَابِهِ", "Kur'an'ı okuyun. Çünkü Kur'an, kendisini okuyanlara kıyâmet gününde şefaat edecektir.", "Recite the Quran, for it will come on the Day of Resurrection as an intercessor for those who recite it.", "Abu Umamah al-Bahili (r.a.)", "Müslim, Müsâfirîn 252"),
        Hadith("لَا تَتْرُكَنَّ صَلَاةً مَكْتُوبَةً مُتَعَمِّدًا فَمَنْ تَرَكَهَا مُتَعَمِّدًا فَقَدْ بَرِئَتْ مِنْهُ الذِّمَّةُ", "Farz namazı kasten terk etme! Farz namazı bile bile terk edeni Allah korumaz.", "Never deliberately abandon an obligatory prayer, for whoever deliberately abandons it, Allah's protection is removed from him.", "Ubadah ibn as-Samit (r.a.)", "İbn Mâce, Fiten 36"),
    )
}
